import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import axiosInstance from '../api/axiosConfig';

const Register = () => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [role, setRole] = useState('STUDENT'); // Defaults to STUDENT
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (password !== confirmPassword) {
      setError('Passwords do not match');
      return;
    }

    if (password.length < 6) {
      setError('Password must be at least 6 characters long');
      return;
    }

    setLoading(true);

    try {
      await axiosInstance.post('/api/auth/register', {
        name,
        email,
        password,
        role
      });
      setSuccess('Registration successful! Redirecting to login...');
      setTimeout(() => {
        navigate('/login');
      }, 2000);
    } catch (err) {
      console.error(err);
      if (err.response && err.response.data) {
        if (err.response.data.validationErrors) {
          const firstErr = Object.values(err.response.data.validationErrors)[0];
          setError(firstErr);
        } else if (err.response.data.message) {
          setError(err.response.data.message);
        } else {
          setError('Registration failed. Please try again.');
        }
      } else {
        setError('Network error. Please try again.');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container py-5">
      <div className="row justify-content-center align-items-center" style={{ minHeight: '80vh' }}>
        <div className="col-12 col-md-8 col-lg-6">
          <div className="card border-0 bg-slate-800 text-light shadow-lg rounded-4 overflow-hidden">
            <div className="card-body p-5">
              <div className="text-center mb-4">
                <span className="fs-1 bg-primary text-white p-3 rounded-4 d-inline-flex mb-3 shadow-sm">
                  📝
                </span>
                <h3 className="fw-bold">Create Account</h3>
                <p className="text-muted">Join our modern learning platform</p>
              </div>

              {error && (
                <div className="alert alert-danger border-0 bg-danger bg-opacity-10 text-danger rounded-3 mb-4" role="alert">
                  {error}
                </div>
              )}

              {success && (
                <div className="alert alert-success border-0 bg-success bg-opacity-10 text-success rounded-3 mb-4" role="alert">
                  {success}
                </div>
              )}

              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="name" className="form-label text-muted small fw-semibold text-uppercase">
                    Full Name
                  </label>
                  <input
                    type="text"
                    className="form-control bg-slate-900 border-secondary border-opacity-20 text-light rounded-3 py-2 px-3 focus-primary"
                    id="name"
                    placeholder="John Doe"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label htmlFor="email" className="form-label text-muted small fw-semibold text-uppercase">
                    Email Address
                  </label>
                  <input
                    type="email"
                    className="form-control bg-slate-900 border-secondary border-opacity-20 text-light rounded-3 py-2 px-3 focus-primary"
                    id="email"
                    placeholder="john@example.com"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label htmlFor="role" className="form-label text-muted small fw-semibold text-uppercase">
                    Role
                  </label>
                  <select
                    className="form-select bg-slate-900 border-secondary border-opacity-20 text-light rounded-3 py-2 px-3 focus-primary"
                    id="role"
                    value={role}
                    onChange={(e) => setRole(e.target.value)}
                    required
                  >
                    <option value="STUDENT">Student</option>
                    <option value="ADMIN">Admin</option>
                  </select>
                </div>

                <div className="row">
                  <div className="col-md-6 mb-3">
                    <label htmlFor="password" className="form-label text-muted small fw-semibold text-uppercase">
                      Password
                    </label>
                    <input
                      type="password"
                      className="form-control bg-slate-900 border-secondary border-opacity-20 text-light rounded-3 py-2 px-3 focus-primary"
                      id="password"
                      placeholder="••••••••"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      required
                    />
                  </div>
                  <div className="col-md-6 mb-3">
                    <label htmlFor="confirmPassword" className="form-label text-muted small fw-semibold text-uppercase">
                      Confirm Password
                    </label>
                    <input
                      type="password"
                      className="form-control bg-slate-900 border-secondary border-opacity-20 text-light rounded-3 py-2 px-3 focus-primary"
                      id="confirmPassword"
                      placeholder="••••••••"
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                      required
                    />
                  </div>
                </div>

                <button
                  type="submit"
                  className="btn btn-primary w-100 py-2.5 rounded-3 fw-semibold shadow-sm mt-3 d-flex align-items-center justify-content-center gap-2"
                  disabled={loading}
                >
                  {loading ? (
                    <>
                      <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                      Registering...
                    </>
                  ) : (
                    'Register'
                  )}
                </button>
              </form>

              <div className="text-center mt-4">
                <span className="text-muted small">Already have an account? </span>
                <Link to="/login" className="text-primary text-decoration-none small fw-semibold">
                  Sign In
                </Link>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Register;
